    def getProbability(self, balls: List[int]) -> float:
        def calc(d):
            n = len(d)
            s = sum(d.values())
            result = math.factorial(s)
            for k, v in list(d.items()):
                result /= math.factorial(v)
            return result

        def choose(i, k, d1, d2):
            if k == 0 and i <= n:
                for j in range(i, n):
                    d2[j] = balls[j]
                t = calc(d1) * calc(d2)
                e = t if len(d1) == len(d2) else 0
                return t, e 
            if k < 0 or i == n:
